<?php $a=function($b,$c){return $b+$c;};$d=array(1,2,3,4,5);foreach($d as $e){echo $a($e,10);}function f(){global $g;$g=array();for($h=0;$h<100;$h++){$g[$h]=$h*2;}return $g;}class i{private $j;public function __construct($k){$this->j=$k;}public function l(){return $this->j*3;}}$m=new i(5);echo $m->l();function n($o){$p=array();foreach($o as $q=>$r){$p[$q]=strtoupper($r);}return $p;}$s=n(array('a'=>'hello','b'=>'world'));var_dump($s);if(!function_exists('t')){function t($u,$v=null){if(is_null($v)){return $u;}else{return $u+$v;}}}echo t(5,3);$w=function($x){$y=array();for($z=0;$z<$x;$z++){$y[]=$z*$z;}return $y;};$aa=$w(10);foreach($aa as $ab){echo $ab."\n";}

